"use client";

import { useState } from "react";
import Header from "@/components/header";
import HeroSection from "@/components/hero-section";
import AboutSection from "@/components/about-section";
import PricingSection from "@/components/pricing-section";
import ProductsSection from "@/components/products-section";
import AcademySection from "@/components/academy-section";
import YoutubeSection from "@/components/youtube-section";
import BranchesSection from "@/components/branches-section";
import ContactSection from "@/components/contact-section";
import Footer from "@/components/footer";
import MobileBottomNav from "@/components/mobile-bottom-nav";
import FloatingActions from "@/components/floating-actions";
import BookingModal from "@/components/booking-modal";

export default function Home() {
  const [isBookingOpen, setIsBookingOpen] = useState(false);
  const openBooking = () => setIsBookingOpen(true);

  return (
    <>
      <Header />
      <main>
        <HeroSection onOpenBooking={openBooking} />
        <AboutSection />
        <PricingSection />
        <ProductsSection />
        <AcademySection />
        <YoutubeSection />
        <BranchesSection />
        <ContactSection />
      </main>
      <Footer />
      {/* Spacer for mobile fixed bottom elements (Call bar + Bottom nav) */}
      <div className="h-36 md:hidden" />
      <MobileBottomNav onOpenBooking={openBooking} />
      <FloatingActions onOpenBooking={openBooking} />
      <BookingModal isOpen={isBookingOpen} onClose={() => setIsBookingOpen(false)} />
    </>
  );
}


### src/components/about-section.tsx ###
"use client";

import { Scissors } from "lucide-react";
import { useEffect, useRef } from "react";

const STATS = [
  { value: "40+", label: "Năm kinh nghiệm" },
  { value: "500+", label: "Khách/tháng" },
  { value: "1", label: "Chi nhánh" },
  { value: "100%", label: "Cam kết hài lòng" },
];

export default function AboutSection() {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.querySelectorAll(".reveal, .reveal-left, .reveal-right").forEach((el) => {
              el.classList.add("is-visible");
            });
          }
        });
      },
      { threshold: 0.1 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={sectionRef} id="about" className="py-20 md:py-28 bg-dark-light overflow-hidden relative">
      <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/15 to-transparent" />

      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14">
          <div className="reveal inline-flex items-center justify-center w-14 h-14 bg-gold/10 rounded-2xl mb-4 border border-gold/20">
            <Scissors className="text-gold" size={26} />
          </div>
          <h2
            className="reveal text-3xl md:text-4xl lg:text-5xl font-black text-white mb-4 uppercase tracking-wider"
            style={{ fontFamily: "Darker Grotesque, sans-serif", animationDelay: "0.1s" }}
          >
            Về <span className="text-gold-gradient">Chúng Tôi</span>
          </h2>
          <div className="reveal section-divider" style={{ animationDelay: "0.2s" }} />
        </div>

        <div className="grid md:grid-cols-2 gap-10 lg:gap-16 items-center">
          {/* Text */}
          <div className="reveal-left space-y-5" style={{ animationDelay: "0.1s" }}>
            <p className="text-white/90 leading-relaxed text-lg">
              <span className="text-gold font-black text-xl" style={{ fontFamily: "Darker Grotesque, sans-serif" }}>
                BarberShop Chú Lùn
              </span>{" "}
              — tiệm tóc nam đã gắn bó với phong cách sống của người Sài Gòn.
            </p>
            <p className="text-white/65 leading-relaxed">
              Tiếp nối truyền thống gia đình lâu đời, cha của họ đã hành nghề
              cắt tóc hơn 40 năm. Với niềm đam mê và tâm huyết, BarberShop Chú Lùn
              đã trở thành địa chỉ tin cậy cho những quý ông sành điệu tại TP. Hồ Chí Minh.
            </p>
            <p className="text-white/65 leading-relaxed">
              Chúng tôi luôn lấy chất lượng phục vụ và sự hài lòng của khách
              hàng làm kim chỉ nam. Mỗi lần bước vào BarberShop Chú Lùn, bạn sẽ
              được trải nghiệm dịch vụ chuyên nghiệp, không gian sang trọng và
              thân thiện.
            </p>

            {/* Stats grid */}
            <div className="grid grid-cols-2 gap-3 pt-2">
              {STATS.map((stat) => (
                <div
                  key={stat.label}
                  className="bg-black/40 border border-white/8 rounded-xl px-4 py-4 hover:border-gold/25 transition-colors"
                >
                  <p
                    className="text-3xl font-black text-gold leading-none mb-1"
                    style={{ fontFamily: "Darker Grotesque, sans-serif" }}
                  >
                    {stat.value}
                  </p>
                  <p className="text-white/50 text-xs">{stat.label}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Image */}
          <div className="reveal-right relative" style={{ animationDelay: "0.2s" }}>
            <div className="relative">
              <div className="aspect-[4/5] rounded-2xl overflow-hidden border border-white/10">
                <div
                  className="w-full h-full bg-cover bg-center transition-transform duration-700 hover:scale-105"
                  style={{
                    backgroundImage:
                      "url('https://images.unsplash.com/photo-1621605815971-fbc98d665033?w=800&q=80')",
                  }}
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent" />
              </div>

              {/* Badge */}
              <div className="absolute -top-3 -left-3 bg-gold text-black px-4 py-2 rounded-xl font-black text-sm shadow-lg shadow-gold/30">
                <span style={{ fontFamily: "Darker Grotesque, sans-serif" }}>Từ 1980</span>
              </div>

              {/* Decorative corners */}
              <div className="absolute -bottom-4 -right-4 w-24 h-24 border-2 border-gold/30 rounded-2xl -z-10" />
              <div className="absolute -bottom-6 -right-6 w-16 h-16 border border-gold/15 rounded-xl -z-10" />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}


