import { useState } from "react";
import { X, Calendar, Clock, User, Phone, Scissors, Send } from "lucide-react";
import { SERVICES, BARBERS, TIME_SLOTS } from "@/data/site-data";

const GOOGLE_SCRIPT_URL = ""; // TODO: Paste Google Apps Script URL here

interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type FormStatus = "idle" | "submitting" | "success" | "error";

export default function BookingModal({ isOpen, onClose }: BookingModalProps) {
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    service: "",
    barber: "",
    date: "",
    time: "",
  });
  const [status, setStatus] = useState<FormStatus>("idle");

  if (!isOpen) return null;

  const today = new Date().toISOString().split("T")[0];

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus("submitting");

    try {
      if (GOOGLE_SCRIPT_URL) {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
      }
      setStatus("success");
      setTimeout(() => {
        setStatus("idle");
        setFormData({ name: "", phone: "", service: "", barber: "", date: "", time: "" });
        onClose();
      }, 2500);
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  const handleClose = () => {
    if (status === "submitting") return;
    setStatus("idle");
    onClose();
  };

  return (
    <div
      className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 transition-all duration-300"
      onClick={handleClose}
    >
      <div
        className="bg-dark-light rounded-2xl max-w-lg w-full max-h-[90vh] overflow-y-auto border border-white/10 transform scale-95 opacity-0 animate-modal-enter"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-white/10">
          <div>
            <h2
              className="text-xl font-bold text-white uppercase tracking-wider"
              style={{ fontFamily: "Darker Grotesque, sans-serif" }}
            >
              Đặt Lịch <span className="text-gold">Cắt Tóc</span>
            </h2>
            <p className="text-white/50 text-sm mt-1">Chọn dịch vụ và thời gian phù hợp</p>
          </div>
          <button
            onClick={handleClose}
            className="text-white/50 hover:text-white p-1 transition-colors"
            aria-label="Đóng"
          >
            <X size={22} />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-5 space-y-6">
          {/* Customer Info Section */}
          <div className="bg-dark-lighter/50 p-4 rounded-lg">
            <h3 className="text-white/70 text-sm font-medium mb-4">Thông Tin Khách Hàng</h3>
            <div className="space-y-4">
              {/* Name */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <User size={14} /> Họ và tên *
                </label>
                <input
                  type="text"
                  required
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Nhập họ tên"
                  className="w-full bg-dark-light border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:ring-2 focus:ring-gold/20 focus:outline-none transition-all"
                />
              </div>

              {/* Phone */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <Phone size={14} /> Số điện thoại *
                </label>
                <input
                  type="tel"
                  required
                  value={formData.phone}
                  onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                  placeholder="Nhập số điện thoại"
                  className="w-full bg-dark-light border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:ring-2 focus:ring-gold/20 focus:outline-none transition-all"
                />
              </div>
            </div>
          </div>

          {/* Service Section */}
          <div className="bg-dark-lighter/50 p-4 rounded-lg">
            <h3 className="text-white/70 text-sm font-medium mb-4">Dịch Vụ</h3>
            <div className="space-y-4">
              {/* Service */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <Scissors size={14} /> Dịch vụ *
                </label>
                <select
                  required
                  value={formData.service}
                  onChange={(e) => setFormData({ ...formData, service: e.target.value })}
                  className="w-full bg-dark-light border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:ring-2 focus:ring-gold/20 focus:outline-none transition-all appearance-none cursor-pointer"
                >
                  <option value="" className="bg-dark-lighter">Chọn dịch vụ</option>
                  {SERVICES.map((s) => (
                    <option key={s.name} value={s.name} className="bg-dark-lighter">
                      {s.name} - {s.price}
                    </option>
                  ))}
                </select>
              </div>

              {/* Barber */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <User size={14} /> Thợ cắt tóc *
                </label>
                <select
                  required
                  value={formData.barber}
                  onChange={(e) => setFormData({ ...formData, barber: e.target.value })}
                  className="w-full bg-dark-light border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:ring-2 focus:ring-gold/20 focus:outline-none transition-all appearance-none cursor-pointer"
                >
                  <option value="" className="bg-dark-lighter">Chọn thợ cắt tóc</option>
                  {BARBERS.map((b) => (
                    <option key={b.id} value={b.name} className="bg-dark-lighter">
                      {b.name}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          {/* Date/Time Section */}
          <div className="bg-dark-lighter/50 p-4 rounded-lg">
            <h3 className="text-white/70 text-sm font-medium mb-4">Thời Gian</h3>
            <div className="space-y-4">
              {/* Date */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <Calendar size={14} /> Ngày *
                </label>
                <input
                  type="date"
                  required
                  min={today}
                  value={formData.date}
                  onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                  className="w-full bg-dark-light border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:ring-2 focus:ring-gold/20 focus:outline-none transition-all cursor-pointer"
                />
              </div>

              {/* Time Slots */}
              <div>
                <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                  <Clock size={14} /> Giờ *
                </label>
                <div className="grid grid-cols-6 gap-2">
                  {TIME_SLOTS.map((slot) => (
                    <button
                      key={slot}
                      type="button"
                      onClick={() => setFormData({ ...formData, time: slot })}
                      className={`py-2 rounded-lg text-sm font-bold transition-all cursor-pointer relative overflow-hidden ${
                        formData.time === slot
                          ? "bg-gold text-black before:content-[''] before:absolute before:inset-0 before:bg-gold/20 before:animate-pulse-gold"
                          : "bg-dark-light border border-white/10 text-white/70 hover:border-gold/30 hover:text-white"
                      }`}
                    >
                      {slot}
                    </button>
                  ))}
                </div>
                <input type="hidden" required value={formData.time} />
              </div>
            </div>
          </div>

          {/* Booking Summary */}
          {formData.time && (
            <div className="bg-dark-light border border-gold/20 rounded-lg p-4 text-white/90 text-sm shadow-inner">
              <h3 className="text-white/80 text-sm font-medium mb-3">Tóm Tắt Đặt Lịch</h3>
              <div className="space-y-2">
                <p><strong className="text-gold">Dịch vụ:</strong> {formData.service || "Chưa chọn"}</p>
                <p><strong className="text-gold">Thợ cắt:</strong> {formData.barber || "Chưa chọn"}</p>
                <p><strong className="text-gold">Ngày:</strong> {formData.date || "Chưa chọn"}</p>
                <p><strong className="text-gold">Giờ:</strong> {formData.time}</p>
              </div>
            </div>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={status === "submitting" || !formData.time}
            className="w-full bg-gold hover:bg-gold-dark active:bg-gold-darker disabled:opacity-50 disabled:cursor-not-allowed text-black font-bold py-3 rounded-lg transition-all flex items-center justify-center gap-2 mt-4 relative overflow-hidden group"
          >
            {status === "submitting" ? (
              <>
                <div className="w-5 h-5 border-2 border-black/30 border-t-black rounded-full animate-spin" />
                Đang gửi...
              </>
            ) : status === "success" ? (
              "Đặt lịch thành công!"
            ) : status === "error" ? (
              "Có lỗi xảy ra, thử lại"
            ) : (
              <>
                <Send size={18} />
                Xác Nhận Đặt Lịch
              </>
            )}
            <span className="absolute inset-0 bg-black/15 opacity-0 group-hover:opacity-100 transition-opacity" />
          </button>
        </form>
      </div>
    </div>
  );
}


