                required
                className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white placeholder-white/25 focus:border-gold focus:outline-none focus:ring-1 focus:ring-gold/20 transition-all resize-none text-sm"
              />
              <button
                type="submit"
                className={`w-full font-black py-4 rounded-xl transition-all duration-300 flex items-center justify-center gap-2 hover:scale-[1.02] active:scale-[0.98] ${
