"use client";

import { useState, useEffect } from "react";
import { NAV_LINKS, SITE_INFO } from "@/data/site-data";
import { Menu, X, Phone } from "lucide-react";

export default function Header() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState("home");

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);

      // Active section tracking
      const sections = NAV_LINKS.map((l) => l.href.replace("#", ""));
      for (const id of [...sections].reverse()) {
        const el = document.getElementById(id);
        if (el && window.scrollY >= el.offsetTop - 120) {
          setActiveSection(id);
          break;
        }
      }
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Close menu on resize to desktop
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) setIsMobileMenuOpen(false);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Prevent body scroll when menu open
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => { document.body.style.overflow = ""; };
  }, [isMobileMenuOpen]);

  const handleNavClick = (href: string) => {
    setIsMobileMenuOpen(false);
    setTimeout(() => {
      const el = document.querySelector(href);
      el?.scrollIntoView({ behavior: "smooth" });
    }, 100);
  };

  return (
    <>
      <header
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
          isScrolled
            ? "bg-black/95 backdrop-blur-md shadow-[0_1px_0_rgba(213,185,129,0.1)]"
            : "bg-gradient-to-b from-black/70 to-transparent"
        }`}
      >
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 flex items-center justify-between h-16 md:h-20">
          {/* Logo */}
          <button
            onClick={() => handleNavClick("#home")}
            className="text-gold font-black text-lg md:text-xl tracking-wider hover:opacity-80 transition-opacity leading-tight"
            style={{ fontFamily: "Darker Grotesque, sans-serif" }}
          >
            <span className="block text-[10px] sm:text-xs text-gold/60 font-medium tracking-[0.3em] uppercase">
              Barbershop
            </span>
            CHÚ LÙN
          </button>

          {/* Desktop Nav */}
          <nav className="hidden lg:flex items-center gap-0.5">
            {NAV_LINKS.map((link) => {
              const sectionId = link.href.replace("#", "");
              const isActive = activeSection === sectionId;
              return (
                <button
                  key={link.href}
                  onClick={() => handleNavClick(link.href)}
                  className={`relative px-3 py-2 text-sm uppercase tracking-wide transition-colors ${
                    isActive ? "text-gold" : "text-white/70 hover:text-white"
                  }`}
                  style={{ fontFamily: "Darker Grotesque, sans-serif" }}
                >
                  {link.label}
                  {isActive && (
                    <span className="absolute bottom-0 left-3 right-3 h-px bg-gold rounded-full" />
                  )}
                </button>
              );
            })}
          </nav>

          {/* Hotline Desktop */}
          <a
            href={`tel:${SITE_INFO.hotline}`}
            className="hidden lg:flex items-center gap-2 bg-gold/10 hover:bg-gold/20 border border-gold/20 hover:border-gold/40 text-gold text-sm px-4 py-2 rounded-lg transition-all"
          >
            <Phone size={14} />
            <span style={{ fontFamily: "Darker Grotesque, sans-serif" }} className="font-bold">
              {SITE_INFO.hotline}
            </span>
          </a>

          {/* Mobile: Hotline + Toggle */}
          <div className="flex items-center gap-3 lg:hidden">
            <a
              href={`tel:${SITE_INFO.hotline}`}
              className="hidden sm:flex items-center gap-1.5 text-gold text-sm border border-gold/30 px-3 py-1.5 rounded-lg"
            >
              <Phone size={13} />
              <span className="font-bold" style={{ fontFamily: "Darker Grotesque, sans-serif" }}>
                {SITE_INFO.hotline}
              </span>
            </a>
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="text-white hover:text-gold transition-colors p-2 rounded-lg hover:bg-white/5"
              aria-label="Toggle menu"
            >
              {isMobileMenuOpen ? <X size={22} /> : <Menu size={22} />}
            </button>
          </div>
        </div>
      </header>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div
          className="fixed inset-0 z-40 lg:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        >
          {/* Backdrop */}
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />

          {/* Drawer */}
          <div
            className="absolute top-0 right-0 h-full w-72 sm:w-80 bg-[#0d0d0d] border-l border-white/10 animate-slide-down flex flex-col"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Drawer header */}
            <div className="flex items-center justify-between px-6 py-5 border-b border-white/10">
              <span
                className="text-gold font-black text-lg tracking-wider"
                style={{ fontFamily: "Darker Grotesque, sans-serif" }}
              >
                MENU
              </span>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="text-white/60 hover:text-white p-1.5 rounded-lg hover:bg-white/5 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            {/* Nav links */}
            <nav className="flex-1 py-4 overflow-y-auto">
              {NAV_LINKS.map((link, idx) => {
                const sectionId = link.href.replace("#", "");
                const isActive = activeSection === sectionId;
                return (
                  <button
                    key={link.href}
                    onClick={() => handleNavClick(link.href)}
                    className={`w-full text-left px-6 py-4 flex items-center gap-3 transition-colors border-l-2 ${
                      isActive
                        ? "border-gold text-gold bg-gold/5"
                        : "border-transparent text-white/70 hover:text-white hover:bg-white/5"
                    }`}
                    style={{
                      fontFamily: "Darker Grotesque, sans-serif",
                      animationDelay: `${idx * 0.05}s`,
                    }}
                  >
                    <span className="text-sm uppercase tracking-wider font-bold">{link.label}</span>
                  </button>
                );
              })}
            </nav>

            {/* Bottom CTA */}
            <div className="p-6 border-t border-white/10">
              <a
                href={`tel:${SITE_INFO.hotline}`}
                className="flex items-center justify-center gap-2 bg-gold hover:bg-gold-dark text-black py-3 px-6 rounded-xl font-black transition-colors w-full"
                style={{ fontFamily: "Darker Grotesque, sans-serif" }}
              >
                <Phone size={18} />
                {SITE_INFO.hotline}
              </a>
            </div>
          </div>
        </div>
      )}
    </>
  );
}


