"use client";

import { useEffect, useState } from "react";
import { Home, Scissors, Calendar, MapPin, MessageCircle } from "lucide-react";

const NAV_ITEMS = [
  { icon: Home, label: "Trang chủ", href: "#home", section: "home" },
  { icon: Scissors, label: "Bảng giá", href: "#pricing", section: "pricing" },
  { icon: MapPin, label: "Chi nhánh", href: "#branches", section: "branches" },
  { icon: MessageCircle, label: "Liên hệ", href: "#contact", section: "contact" },
];

export default function MobileBottomNav({ onOpenBooking }: { onOpenBooking: () => void }) {
  const [activeSection, setActiveSection] = useState("home");

  useEffect(() => {
    const sectionIds = ["home", "about", "pricing", "products", "academy", "branches", "contact"];
    const handleScroll = () => {
      for (const id of [...sectionIds].reverse()) {
        const el = document.getElementById(id);
        if (el && window.scrollY >= el.offsetTop - 150) {
          setActiveSection(id);
          break;
        }
      }
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const handleNav = (href: string) => {
    const el = document.querySelector(href);
    el?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 md:hidden pb-safe">
      <div className="bg-[#0d0d0d]/97 backdrop-blur-xl border-t border-white/10 shadow-[0_-4px_24px_rgba(0,0,0,0.6)]">
        <div className="flex items-center justify-around px-2 py-1.5">
          {NAV_ITEMS.map((item) => {
            const isActive = activeSection === item.section;
            return (
              <button
                key={item.label}
                onClick={() => handleNav(item.href)}
                className={`flex flex-col items-center gap-0.5 px-3 py-1.5 rounded-xl transition-all duration-200 min-w-[56px] cursor-pointer ${
                  isActive ? "text-gold" : "text-white/45 hover:text-white/80"
                }`}
              >
                <div className={`transition-all duration-200 ${isActive ? "bg-gold/15 p-1.5 rounded-lg -mb-0.5" : ""}`}>
                  <item.icon size={18} strokeWidth={isActive ? 2.5 : 1.8} />
                </div>
                <span
                  className="text-[9px] font-medium leading-none mt-1"
                  style={{ fontFamily: "Darker Grotesque, sans-serif" }}
                >
                  {item.label}
                </span>
              </button>
            );
          })}

          {/* Book CTA button */}
          <button
            onClick={onOpenBooking}
            className="flex flex-col items-center gap-1 cursor-pointer"
          >
            <div className="bg-gold hover:bg-gold-dark text-black rounded-xl px-3.5 py-1.5 flex items-center gap-1.5 shadow-md shadow-gold/25 transition-colors active:scale-95">
              <Calendar size={14} />
              <span
                className="text-[10px] font-black uppercase tracking-wide"
                style={{ fontFamily: "Darker Grotesque, sans-serif" }}
              >
                Đặt lịch
              </span>
            </div>
          </button>
        </div>
      </div>
    </nav>
  );
}


