const CATEGORIES = [
  {
    icon: Scissors,
    label: "Cắt & Tạo Kiểu",
    items: ["Cắt tóc nam", "Cắt tóc + Gội massage"],
  },
  {
    icon: Sparkles,
    label: "Uốn & Nhuộm",
    items: [
      "Uốn tóc Hàn Quốc",
      "Uốn tóc Setting",
      "Duỗi tóc",
      "Nhuộm tóc màu",
      "Nhuộm tóc Highlight",
      "Nhuộm tóc Platinum",
    ],
  },
  {
    icon: Star,
    label: "Chăm Sóc & Combo",
    items: ["Cạo mặt", "Wax mũi", "Combo VIP (Cắt + Gội + Cạo mặt + Wax mũi)"],
  },
];

export default function PricingSection() {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.querySelectorAll(".reveal").forEach((el) => {
              el.classList.add("is-visible");
            });
          }
        });
      },
      { threshold: 0.1 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={sectionRef} id="pricing" className="py-20 md:py-28 bg-black relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/20 to-transparent" />
      <div className="absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/20 to-transparent" />
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] rounded-full bg-gold/2 blur-[100px] pointer-events-none" />

      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        {/* Header */}
        <div className="text-center mb-14 reveal" style={{ animationDelay: "0s" }}>
          <p className="text-gold/60 uppercase tracking-[0.3em] text-xs mb-3">
            Dịch vụ
          </p>
          <h2
            className="text-3xl md:text-4xl lg:text-5xl font-black text-white mb-4 uppercase tracking-wider"
            style={{ fontFamily: "Darker Grotesque, sans-serif" }}
          >
            Bảng Giá <span className="text-gold-gradient">Dịch Vụ</span>
          </h2>
          <div className="section-divider" />
          <p className="text-white/40 text-sm mt-4">
            Giá niêm yết — chất lượng đảm bảo
          </p>
        </div>

        {/* Categories grid */}
        <div className="grid md:grid-cols-3 gap-5">
          {CATEGORIES.map((cat, catIdx) => {
            const Icon = cat.icon;
            const catServices = SERVICES.filter((s) => cat.items.includes(s.name));

            return (
              <div
                key={cat.label}
                className={`reveal bg-dark-light rounded-2xl overflow-hidden border border-white/5 hover:border-gold/20 transition-all duration-300 flex flex-col`}
                style={{ animationDelay: `${catIdx * 0.15}s` }}
              >
                {/* Category header */}
                <div className="px-5 py-4 bg-gradient-to-r from-gold/10 to-transparent border-b border-white/5 flex items-center gap-3">
                  <div className="bg-gold/15 p-2 rounded-lg">
                    <Icon className="text-gold" size={18} />
                  </div>
                  <h3
                    className="text-gold font-black text-sm uppercase tracking-wider"
                    style={{ fontFamily: "Darker Grotesque, sans-serif" }}
                  >
                    {cat.label}
                  </h3>
                </div>

                {/* Services list */}
                <div className="flex-1 divide-y divide-white/5">
                  {catServices.map((service) => (
                    <div
                      key={service.name}
                      className="flex items-center justify-between px-5 py-3.5 hover:bg-white/3 transition-colors group"
                    >
                      <p className="text-white/75 text-sm group-hover:text-white transition-colors leading-snug pr-4 flex-1">
                        {service.name}
                      </p>
                      <p
                        className="text-gold font-black text-base whitespace-nowrap shrink-0"
                        style={{ fontFamily: "Darker Grotesque, sans-serif" }}
